import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"08 — ZeroHeight: The Human-Friendly Documentation Hub","description":"","frontmatter":{},"headers":[],"relativePath":"08-zeroheight.md","filePath":"08-zeroheight.md"}'),i={name:"08-zeroheight.md"};function o(p,e,l,d,r,h){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="_08-—-zeroheight-the-human-friendly-documentation-hub" tabindex="-1">08 — ZeroHeight: The Human-Friendly Documentation Hub <a class="header-anchor" href="#_08-—-zeroheight-the-human-friendly-documentation-hub" aria-label="Permalink to &quot;08 — ZeroHeight: The Human-Friendly Documentation Hub&quot;">​</a></h1><p>ZeroHeight is where the design system comes alive for everyone — not just developers. This guide explains what ZeroHeight is, how our site is structured, and how to add documentation for new components.</p><p><strong>Where to find it:</strong> <code>motadata.zeroheight.com</code></p><hr><h2 id="what-zeroheight-is" tabindex="-1">What ZeroHeight Is <a class="header-anchor" href="#what-zeroheight-is" aria-label="Permalink to &quot;What ZeroHeight Is&quot;">​</a></h2><p>ZeroHeight is a documentation platform built specifically for design systems. It sits between Figma and code, providing a place for:</p><ul><li>Written guidelines: when to use a component, when not to, best practices</li><li>Live embedded Storybook examples that update automatically</li><li>Embedded Figma frames showing design specs</li><li>Code snippets for developers to copy</li></ul><h3 id="why-zeroheight-instead-of-just-storybook-or-readme" tabindex="-1">Why ZeroHeight Instead of Just Storybook or README? <a class="header-anchor" href="#why-zeroheight-instead-of-just-storybook-or-readme" aria-label="Permalink to &quot;Why ZeroHeight Instead of Just Storybook or README?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Storybook</th><th>README</th><th>ZeroHeight</th></tr></thead><tbody><tr><td>Live interactive components</td><td>Yes</td><td>No</td><td>Yes (embedded)</td></tr><tr><td>Written guidelines</td><td>Limited</td><td>Yes</td><td>Yes</td></tr><tr><td>Embedded Figma frames</td><td>No</td><td>No</td><td>Yes</td></tr><tr><td>Friendly for non-developers</td><td>No</td><td>No</td><td>Yes</td></tr><tr><td>Figma integration</td><td>No</td><td>No</td><td>Yes</td></tr><tr><td>Organized navigation</td><td>Yes</td><td>No</td><td>Yes</td></tr></tbody></table><p>Storybook is a great tool for developers experimenting with components. But a product manager, designer, or QA engineer who wants to understand &quot;when should I use a Primary button vs a Ghost button?&quot; doesn&#39;t want to dig through code. ZeroHeight gives them that answer in plain language.</p><hr><h2 id="structure-of-the-mdt-zeroheight-site" tabindex="-1">Structure of the MDT ZeroHeight Site <a class="header-anchor" href="#structure-of-the-mdt-zeroheight-site" aria-label="Permalink to &quot;Structure of the MDT ZeroHeight Site&quot;">​</a></h2><p>The site is organized into two main sections:</p><h3 id="foundations" tabindex="-1">Foundations <a class="header-anchor" href="#foundations" aria-label="Permalink to &quot;Foundations&quot;">​</a></h3><p>Pages covering the fundamental design decisions:</p><ul><li><strong>Colors</strong> — the full color palette, semantic color tokens, usage guidance</li><li><strong>Typography</strong> — type scale, font weights, line heights, heading vs. body</li><li><strong>Spacing</strong> — the spacing scale, how to use spacing tokens</li><li><strong>Iconography</strong> — icon library and usage rules</li></ul><h3 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h3><p>One page per component, each with multiple tabs:</p><p><strong>Guidelines tab:</strong> Written documentation</p><ul><li>Overview of what the component does</li><li>When to use it</li><li>When NOT to use it (important — avoids misuse)</li><li>Best practices</li><li>Accessibility considerations</li></ul><p><strong>Specs tab:</strong> Design specifications</p><ul><li>Embedded Figma frame showing all variants and measurements</li><li>Embedded Storybook story for interactive exploration</li></ul><p><strong>Code tab:</strong> Implementation reference</p><ul><li>npm install snippet</li><li>Import example</li><li>Props table</li><li>Usage examples</li></ul><hr><h2 id="adding-a-new-component-page" tabindex="-1">Adding a New Component Page <a class="header-anchor" href="#adding-a-new-component-page" aria-label="Permalink to &quot;Adding a New Component Page&quot;">​</a></h2><p>Here&#39;s the step-by-step process for adding documentation for a new component (using Badge as the example).</p><h3 id="step-1-log-in-to-zeroheight" tabindex="-1">Step 1: Log In to ZeroHeight <a class="header-anchor" href="#step-1-log-in-to-zeroheight" aria-label="Permalink to &quot;Step 1: Log In to ZeroHeight&quot;">​</a></h3><p>Go to <code>motadata.zeroheight.com</code> and click &quot;Log in.&quot; Use the team account credentials (ask a team admin if you don&#39;t have them).</p><h3 id="step-2-create-a-new-page" tabindex="-1">Step 2: Create a New Page <a class="header-anchor" href="#step-2-create-a-new-page" aria-label="Permalink to &quot;Step 2: Create a New Page&quot;">​</a></h3><ol><li>In the left navigation sidebar, find the &quot;Components&quot; section</li><li>Hover over it — a &quot;+&quot; icon appears</li><li>Click &quot;+&quot; to add a new page</li><li>Name it <strong>Badge</strong> (use PascalCase to match the component name)</li><li>Press Enter</li></ol><h3 id="step-3-write-the-guidelines-tab" tabindex="-1">Step 3: Write the Guidelines Tab <a class="header-anchor" href="#step-3-write-the-guidelines-tab" aria-label="Permalink to &quot;Step 3: Write the Guidelines Tab&quot;">​</a></h3><p>The Guidelines tab is the first thing people see. Write it for a non-technical audience.</p><p><strong>Suggested structure:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Overview</span></span>
<span class="line"><span>A brief 1-2 sentence description. Example:</span></span>
<span class="line"><span>&quot;Badges are small labels used to highlight a status, category, or count.</span></span>
<span class="line"><span>They draw attention to important information without taking up much space.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## When to use</span></span>
<span class="line"><span>- To show status (Active, Pending, Failed)</span></span>
<span class="line"><span>- To indicate categories (New, Beta, Deprecated)</span></span>
<span class="line"><span>- To display counts in a compact space</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## When not to use</span></span>
<span class="line"><span>- Don&#39;t use badges as buttons — if it&#39;s clickable, use a Button or Chip</span></span>
<span class="line"><span>- Don&#39;t use badges for long text — keep it to 1-3 words</span></span>
<span class="line"><span>- Don&#39;t stack more than 2-3 badges next to each other</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Best practices</span></span>
<span class="line"><span>- Keep text short and scannable</span></span>
<span class="line"><span>- Use semantic colors consistently: danger for errors, success for confirmations</span></span>
<span class="line"><span>- Pair with a label when the context isn&#39;t obvious: &quot;Status: Active&quot; not just &quot;Active&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Accessibility</span></span>
<span class="line"><span>- Badges are non-interactive by default (span element)</span></span>
<span class="line"><span>- If a badge conveys status, add aria-label for screen readers:</span></span>
<span class="line"><span>  &lt;Badge aria-label=&quot;Status: Active&quot;&gt;Active&lt;/Badge&gt;</span></span></code></pre></div><h3 id="step-4-add-the-specs-tab-—-figma-embed" tabindex="-1">Step 4: Add the Specs Tab — Figma Embed <a class="header-anchor" href="#step-4-add-the-specs-tab-—-figma-embed" aria-label="Permalink to &quot;Step 4: Add the Specs Tab — Figma Embed&quot;">​</a></h3><p>The Specs tab shows the design visuals.</p><p><strong>Embed a Figma frame:</strong></p><ol><li>In ZeroHeight, switch to the &quot;Specs&quot; tab</li><li>Click &quot;+&quot; to add a block → choose &quot;Figma&quot; widget</li><li>In Figma: open the Badge component → right-click → Copy link to selection</li><li>Paste the Figma URL into the ZeroHeight widget</li><li>The Figma frame renders live — when designers update the design, it updates here automatically</li></ol><p><strong>Embed a Storybook story (see next section for the URL format):</strong></p><ol><li>Add another block → choose &quot;iFrame&quot; or &quot;Embed&quot;</li><li>Paste the Storybook iframe URL</li></ol><h3 id="step-5-add-the-specs-tab-—-storybook-embed" tabindex="-1">Step 5: Add the Specs Tab — Storybook Embed <a class="header-anchor" href="#step-5-add-the-specs-tab-—-storybook-embed" aria-label="Permalink to &quot;Step 5: Add the Specs Tab — Storybook Embed&quot;">​</a></h3><p>To embed a Storybook story in ZeroHeight, you need the iframe URL format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://synapse.heynirav.com/iframe.html?id=STORY-ID&amp;viewMode=story</span></span></code></pre></div><p><strong>How to find the story ID:</strong></p><ol><li>Open the deployed Storybook at <code>synapse.heynirav.com</code></li><li>Navigate to your component (e.g., Components &gt; Badge &gt; Playground)</li><li>Look at the URL in your browser — it contains something like:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>?path=/story/components-badge--playground</span></span></code></pre></div></li><li>The story ID is: <code>components-badge--playground</code></li><li>The iframe URL is:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://synapse.heynirav.com/iframe.html?id=components-badge--playground&amp;viewMode=story</span></span></code></pre></div></li></ol><p><strong>Naming convention for story IDs:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[section]-[component-lowercase]--[story-name-lowercase-with-dashes]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Examples:</span></span>
<span class="line"><span>components-button--playground</span></span>
<span class="line"><span>components-button--all-variants</span></span>
<span class="line"><span>components-badge--all-sizes</span></span></code></pre></div><p><strong>Useful iframe URL parameters:</strong></p><ul><li><code>&amp;viewMode=story</code> — shows just the story (no sidebar)</li><li><code>&amp;viewMode=docs</code> — shows the full docs page</li><li><code>&amp;args=variant:success</code> — pre-sets a control value</li></ul><p>Example with pre-set args:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://synapse.heynirav.com/iframe.html?id=components-badge--playground&amp;viewMode=story&amp;args=variant:success</span></span></code></pre></div><h3 id="step-6-add-the-code-tab" tabindex="-1">Step 6: Add the Code Tab <a class="header-anchor" href="#step-6-add-the-code-tab" aria-label="Permalink to &quot;Step 6: Add the Code Tab&quot;">​</a></h3><p>The Code tab is for developers. Include:</p><p><strong>npm installation:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install @niravbhatt/mdt-design-system</span></span></code></pre></div><p><strong>Import:</strong></p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Badge } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@niravbhatt/mdt-design-system&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@niravbhatt/mdt-design-system/styles&#39;</span></span></code></pre></div><p><strong>Basic usage examples:</strong></p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Default&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> variant</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Active&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> variant</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;danger&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> size</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Error&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Badge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><strong>Props table</strong> (add a table block):</p><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>variant</code></td><td><code>&#39;default&#39; | &#39;success&#39; | &#39;warning&#39; | &#39;danger&#39;</code></td><td><code>&#39;default&#39;</code></td><td>Visual style</td></tr><tr><td><code>size</code></td><td><code>&#39;sm&#39; | &#39;md&#39;</code></td><td><code>&#39;md&#39;</code></td><td>Size of the badge</td></tr><tr><td><code>children</code></td><td><code>ReactNode</code></td><td>—</td><td>Text content of the badge</td></tr><tr><td><code>className</code></td><td><code>string</code></td><td>—</td><td>Additional CSS class</td></tr></tbody></table><hr><h2 id="the-live-code-sandbox-and-cdn-url" tabindex="-1">The Live Code Sandbox and CDN URL <a class="header-anchor" href="#the-live-code-sandbox-and-cdn-url" aria-label="Permalink to &quot;The Live Code Sandbox and CDN URL&quot;">​</a></h2><p>ZeroHeight supports live code examples where visitors can edit code and see the component render. For this to work, it needs to load the design system&#39;s CSS.</p><h3 id="how-the-cdn-works" tabindex="-1">How the CDN Works <a class="header-anchor" href="#how-the-cdn-works" aria-label="Permalink to &quot;How the CDN Works&quot;">​</a></h3><p>The CSS file is hosted on jsDelivr, a free CDN for npm packages:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cdn.jsdelivr.net/npm/@niravbhatt/mdt-design-system@VERSION/dist/mdt-design-system.css</span></span></code></pre></div><p>The <code>VERSION</code> part must match the published npm version. When you publish <code>0.2.0</code>, the CDN URL becomes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cdn.jsdelivr.net/npm/@niravbhatt/mdt-design-system@0.2.0/dist/mdt-design-system.css</span></span></code></pre></div><p>jsDelivr caches files permanently for each version. This means:</p><ul><li>Old versions always remain accessible</li><li>The live examples will keep working even as you release new versions</li><li>You must update the URL when you want ZeroHeight to use new styles</li></ul><h3 id="updating-the-cdn-url-after-publishing" tabindex="-1">Updating the CDN URL After Publishing <a class="header-anchor" href="#updating-the-cdn-url-after-publishing" aria-label="Permalink to &quot;Updating the CDN URL After Publishing&quot;">​</a></h3><p>After every npm publish with CSS changes:</p><ol><li>Log in to <code>motadata.zeroheight.com</code></li><li>Go to <strong>Settings</strong> (gear icon, usually bottom-left)</li><li>Find the <strong>Code</strong> settings section</li><li>Find the CSS stylesheet URL</li><li>Update the version number: change <code>@0.1.1</code> to <code>@0.2.0</code> (or whatever the new version is)</li><li>Save</li></ol><p>Without this step, your live code examples in ZeroHeight will use the old CSS, and new components or style changes won&#39;t appear correctly.</p><hr><h2 id="connecting-figma-embeds" tabindex="-1">Connecting Figma Embeds <a class="header-anchor" href="#connecting-figma-embeds" aria-label="Permalink to &quot;Connecting Figma Embeds&quot;">​</a></h2><p>Figma frames embedded in ZeroHeight update live when the design changes — unlike static screenshots that go stale.</p><h3 id="how-to-embed-a-figma-frame" tabindex="-1">How to Embed a Figma Frame <a class="header-anchor" href="#how-to-embed-a-figma-frame" aria-label="Permalink to &quot;How to Embed a Figma Frame&quot;">​</a></h3><ol><li>In Figma: select the frame you want to embed</li><li>Right-click → <strong>Copy link to selection</strong> The URL looks like: <code>https://www.figma.com/design/A8iOt3oQHHT20N1mSpxnQ1/...?node-id=2022-2455</code></li><li>In ZeroHeight: add a Figma block and paste the URL</li><li>ZeroHeight fetches the frame and renders it</li></ol><h3 id="what-gets-embedded" tabindex="-1">What Gets Embedded <a class="header-anchor" href="#what-gets-embedded" aria-label="Permalink to &quot;What Gets Embedded&quot;">​</a></h3><ul><li>The exact frame you linked</li><li>At its designed dimensions</li><li>With a &quot;Open in Figma&quot; link for developers who want to inspect it</li></ul><h3 id="permissions-requirement" tabindex="-1">Permissions Requirement <a class="header-anchor" href="#permissions-requirement" aria-label="Permalink to &quot;Permissions Requirement&quot;">​</a></h3><p>For ZeroHeight to read the Figma frame, the ZeroHeight account must have at least &quot;View&quot; access to the Figma file. If frames show as &quot;unable to load,&quot; it&#39;s a permissions issue — grant ZeroHeight&#39;s connected Figma account access to the file.</p><hr><h2 id="the-zeroheight-toolbar-button-in-storybook" tabindex="-1">The ZeroHeight Toolbar Button in Storybook <a class="header-anchor" href="#the-zeroheight-toolbar-button-in-storybook" aria-label="Permalink to &quot;The ZeroHeight Toolbar Button in Storybook&quot;">​</a></h2><p>There is a button in the Storybook toolbar that links directly to ZeroHeight. It appears in the top-right area of the Storybook UI and is labeled with a small arrow icon.</p><p><strong>What it does:</strong> Clicking it opens <code>motadata.zeroheight.com</code> in a new browser tab.</p><p><strong>How it&#39;s implemented:</strong> The button is defined in <code>.storybook/manager.ts</code>. It uses Storybook&#39;s addon API to add a custom toolbar item.</p><p><strong>Why it&#39;s useful:</strong> It gives developers a one-click path from looking at a component in Storybook to reading its design guidelines in ZeroHeight. Both tools complement each other — Storybook for exploring code, ZeroHeight for understanding intent.</p><hr><h2 id="zeroheight-page-template" tabindex="-1">ZeroHeight Page Template <a class="header-anchor" href="#zeroheight-page-template" aria-label="Permalink to &quot;ZeroHeight Page Template&quot;">​</a></h2><p>Here is a reusable template structure for every new component page:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Component Name]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GUIDELINES TAB</span></span>
<span class="line"><span>  ## Overview</span></span>
<span class="line"><span>  [1-2 sentence description]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## When to use</span></span>
<span class="line"><span>  - [use case 1]</span></span>
<span class="line"><span>  - [use case 2]</span></span>
<span class="line"><span>  - [use case 3]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## When not to use</span></span>
<span class="line"><span>  - [anti-pattern 1]</span></span>
<span class="line"><span>  - [anti-pattern 2]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## Best practices</span></span>
<span class="line"><span>  - [practice 1]</span></span>
<span class="line"><span>  - [practice 2]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## Accessibility</span></span>
<span class="line"><span>  - [accessibility note 1]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SPECS TAB</span></span>
<span class="line"><span>  [Figma embed: component set with all variants]</span></span>
<span class="line"><span>  [Storybook embed: Playground story]</span></span>
<span class="line"><span>  [Storybook embed: All Variants story]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CODE TAB</span></span>
<span class="line"><span>  ## Installation</span></span>
<span class="line"><span>  npm install @niravbhatt/mdt-design-system</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## Import</span></span>
<span class="line"><span>  import { [ComponentName] } from &#39;@niravbhatt/mdt-design-system&#39;</span></span>
<span class="line"><span>  import &#39;@niravbhatt/mdt-design-system/styles&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## Usage</span></span>
<span class="line"><span>  [code examples]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ## Props</span></span>
<span class="line"><span>  [props table]</span></span></code></pre></div><hr><p>Next: <a href="./09-ai-tools-usage">09 — AI Tools Usage</a> — How to use Claude Code, Figma Make, and other AI tools effectively with this design system.</p>`,97)])])}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
